export function getWashingtonDcHormoneClinicsByCity(citySlug: string): HormoneClinic[] {
  return washingtonDcHormoneClinics.filter(c => c.citySlug === citySlug);
}

export function getWashingtonDcHormoneCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of washingtonDcHormoneClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
